WHERE prev_snapshot_id = #{prevSnapshotId}
  AND curr_snapshot_id = #{currSnapshotId}
LIMIT 1

mapper.insert:
INSERT INTO t_disclosure_audit_compare (
    tenant_id, prev_snapshot_id, curr_snapshot_id, diff_json,
    write_count, read_count, no_change_count,
